// First() - throws exception if empty
try
{
    var emp = employees.First(e => e.Salary > 500000);
    Console.WriteLine(emp.Name);
}
catch(InvalidOperationException ex)
{
    Console.WriteLine("No element found!");
}

// FirstOrDefault() - returns null if empty
var emp2 = employees.FirstOrDefault(e => e.Salary > 500000);
if(emp2 != null)
    Console.WriteLine(emp2.Name);
else
    Console.WriteLine("No employee found.");

// Single() - expects exactly one match
