List<int> numbers = new List<int>{1, 2, 3, 4, 5};

// Query is defined but NOT executed yet
var query = numbers.Where(x => x > 2);

// Adding a new item before execution
numbers.Add(6);

// Query executes NOW during foreach
foreach(var item in query)
{
    Console.WriteLine(item);
}
// Output: 3, 4, 5, 6 (includes 6 because query runs here)

List<int> numbers = new List<int>{1, 2, 3, 4, 5};

// Immediate execution using ToList()
var result = numbers.Where(x => x > 2).ToList();

// Adding a new item after execution
numbers.Add(6);

foreach(var item in result)
{
    Console.WriteLine(item);
}
// Output: 3, 4, 5 (does NOT include 6 because query already executed)

// Pagination helper method
int pageNumber = 3;
int pageSize = 5;

// Page 1: Skip(0).Take(5) -> records 1-5
// Page 2: Skip(5).Take(5) -> records 6-10
// Page 3: Skip(10).Take(5) -> records 11-15

var pagedData = employees
    .Skip((pageNumber - 1) * pageSize)
    .Take(pageSize)
    .ToList();

Console.WriteLine("Page " + pageNumber + " Results:");
foreach(var emp in pagedData)
{
    Console.WriteLine(emp.Name + " - " + emp.Salary);
}
